-- Warehouse with auto-suspend
CREATE OR REPLACE WAREHOUSE analytics_wh
  WAREHOUSE_SIZE = 'MEDIUM'
  AUTO_SUSPEND = 60
  AUTO_RESUME = TRUE;

-- Zero-copy clone for dev environment
CREATE DATABASE prod_clone CLONE prod;

-- Time Travel query
SELECT * FROM orders
  AT (OFFSET => -3600);  -- 1 hour ago

-- Restore dropped table
UNDROP TABLE orders;

-- Data Sharing
CREATE SHARE analytics_share;
GRANT USAGE ON DATABASE prod TO SHARE analytics_share;
GRANT SELECT ON ALL TABLES IN SCHEMA prod.public TO SHARE analytics_share;
ALTER SHARE analytics_share ADD ACCOUNTS = org2.account1;

-- Snowflake: Time Travel
SELECT * FROM orders AT(TIMESTAMP => '2024-01-01 00:00:00'::TIMESTAMP_NTZ);

-- Delta Lake equivalent (Databricks SQL)
SELECT * FROM orders TIMESTAMP AS OF '2024-01-01 00:00:00';

-- Delta: manual compaction + Z-ordering (Snowflake handles this automatically via clustering keys)
OPTIMIZE catalog.sales.orders ZORDER BY (customer_id, order_date);

-- Delta: inspect table history (analogous to Snowflake ACCOUNT_USAGE.ACCESS_HISTORY)
DESCRIBE HISTORY catalog.sales.orders;

-- Unity Catalog: grant (Snowflake RBAC equivalent)
GRANT SELECT ON TABLE catalog.sales.orders TO `analyst@company.com`;

