-- Add a clustering key aligned to your dominant query predicate
ALTER TABLE events CLUSTER BY (event_date, user_id);

-- Inspect clustering health — target average_depth close to 1
SELECT SYSTEM$CLUSTERING_INFORMATION('events', '(event_date, user_id)');

-- Confirm pruning in the query plan (look for partitionsScanned vs partitionsTotal)
EXPLAIN
SELECT user_id, event_type, COUNT(*)
FROM events
WHERE event_date BETWEEN '2024-01-01' AND '2024-03-31'
GROUP BY 1, 2;

-- Suspend auto-clustering on cold/archive tables to avoid unnecessary credit spend
ALTER TABLE events SUSPEND RECLUSTER;

-- 1. Role hierarchy
CREATE ROLE analyst;
GRANT ROLE read_prod TO ROLE analyst;
GRANT ROLE analyst TO USER jane;

-- 2. Column masking policy (hide salary for non-HR roles)
CREATE MASKING POLICY mask_salary AS (val NUMBER)
  RETURNS NUMBER ->
  CASE WHEN CURRENT_ROLE() = 'HR_ROLE' THEN val ELSE -1 END;

ALTER TABLE employees MODIFY COLUMN salary
  SET MASKING POLICY mask_salary;

-- 3. Row access policy (each user sees only their region)
CREATE ROW ACCESS POLICY region_filter AS (region STRING)
  RETURNS BOOLEAN ->
  region = CURRENT_ROLE();

ALTER TABLE sales ADD ROW ACCESS POLICY region_filter ON (region);

-- Provider account: create and populate a share
CREATE SHARE product_analytics_share;
GRANT USAGE ON DATABASE analytics_db TO SHARE product_analytics_share;
GRANT USAGE ON SCHEMA analytics_db.public TO SHARE product_analytics_share;

-- Use SECURE VIEW to hide filter logic from consumer
CREATE SECURE VIEW analytics_db.public.daily_metrics AS
  SELECT date, event_type, COUNT(*) AS event_count
  FROM raw_events
  WHERE tenant_id = CURRENT_ACCOUNT()  -- hidden from consumer
  GROUP BY 1, 2;

GRANT SELECT ON VIEW analytics_db.public.daily_metrics TO SHARE product_analytics_share;

-- Grant to consumer account (get account ID from partner)
ALTER SHARE product_analytics_share ADD ACCOUNTS = ORG1.CONSUMER_ACCT;

-- Consumer account: mount the share
CREATE DATABASE metrics_from_provider FROM SHARE ORG1.PROVIDER_ACCT.product_analytics_share;

-- One-time setup: dedicated role + warehouse for dbt
CREATE ROLE dbt_role;
CREATE WAREHOUSE dbt_wh
  WAREHOUSE_SIZE = 'SMALL'
  AUTO_SUSPEND = 120
  AUTO_RESUME = TRUE;

GRANT USAGE ON WAREHOUSE dbt_wh TO ROLE dbt_role;
GRANT USAGE ON DATABASE analytics TO ROLE dbt_role;
GRANT USAGE ON ALL SCHEMAS IN DATABASE analytics TO ROLE dbt_role;
GRANT SELECT ON ALL TABLES IN SCHEMA analytics.raw TO ROLE dbt_role;
GRANT CREATE TABLE ON SCHEMA analytics.transformed TO ROLE dbt_role;

-- Tag every dbt session for observability
ALTER SESSION SET QUERY_TAG = 'dbt_prod';

-- Zero-copy clone prod → staging (no storage cost until writes diverge)
CREATE OR REPLACE TABLE analytics.orders_staging
  CLONE analytics.orders_prod;

-- Time Travel: audit state 24 hours ago (Enterprise supports up to 90 days)
SELECT * FROM analytics.orders_prod
  AT (OFFSET => -86400);

-- Secure Data Share: expose aggregated view to a partner account — zero data movement
CREATE SECURE VIEW shared_schema.partner_metrics AS
  SELECT region, SUM(revenue) AS total_revenue
  FROM internal.sales
  GROUP BY region;

-- Grant share to external Snowflake account
GRANT SELECT ON VIEW shared_schema.partner_metrics TO SHARE partner_share;
